1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteItem {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: QuoteItem[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const basePremiums: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const PROCESSING_FEE = 5;
65	
66	const BLOCK_SIZE = 3;
67	
68	const BLOCK_OF_THREE_BASE = 60;
69	
70	const componentTypes = new Set(["rune", "moonstone"]);
71	
72	const countByType = (items: QuoteItem[]): Record<string, number> =>
73	  items.reduce<Record<string, number>>((counts, item) => {
74	    counts[item.type] = (counts[item.type] ?? 0) + 1;
75	    return counts;
76	  }, {});
77	
78	const basePremiumForGroup = (type: string, count: number): number => {
79	  if (componentTypes.has(type) && count === BLOCK_SIZE) {
80	    return BLOCK_OF_THREE_BASE;
81	  }
82	  return basePremiums[type] * count;
83	};
84	
85	const CURSE_SURCHARGE_RATE = 0.5;
86	
87	const FIRST_INSURANCE_RATE = 0.1;
88	
89	const HIGH_ENCHANTMENT_THRESHOLD = 5;
90	
91	const HIGH_ENCHANTMENT_RATE = 0.3;
92	
93	const itemBasePremium = (item: QuoteItem): number => basePremiums[item.type];
94	
95	const isCursed = (item: QuoteItem): boolean => item.cursed === true;
96	
97	const curseSurcharge = (item: QuoteItem): number =>
98	  isCursed(item) ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
99	
100	const enchantmentLevel = (item: QuoteItem): number => item.enchantment ?? 0;
101	
102	const highEnchantmentSurcharge = (item: QuoteItem): number =>
103	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
104	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_RATE
105	    : 0;
106	
107	const firstInsuranceSurcharge = (item: QuoteItem): number =>
108	  itemBasePremium(item) * FIRST_INSURANCE_RATE;
109	
110	const itemSurcharges = (item: QuoteItem): number =>
111	  curseSurcharge(item) +
112	  highEnchantmentSurcharge(item) +
113	  firstInsuranceSurcharge(item);
114	
115	const sumOfBasePremiums = (items: QuoteItem[]): number => {
116	  const counts = countByType(items);
117	  return Object.entries(counts).reduce(
118	    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
119	    0
120	  );
121	};
122	
123	const sumOfItemSurcharges = (items: QuoteItem[]): number =>
124	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
125	
126	const LOYALTY_YEARS_THRESHOLD = 2;
127	
128	const LOYALTY_DISCOUNT_RATE = 0.2;
129	
130	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
131	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
132	    ? basePremium * LOYALTY_DISCOUNT_RATE
133	    : 0;
134	
135	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
136	
137	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
138	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
139	
140	const quotePremium = (
141	  items: QuoteItem[],
142	  customer: Customer,
143	  isFollowUp: boolean
144	): number => {
145	  const basePremium = sumOfBasePremiums(items);
146	  const surcharges = sumOfItemSurcharges(items);
147	  const discount =
148	    loyaltyDiscount(customer, basePremium) +
149	    followUpDiscount(basePremium, isFollowUp);
150	  return Math.ceil(basePremium + surcharges - discount + PROCESSING_FEE);
151	};
152	
153	const isFollowUpQuote = (steps: Step[], index: number): boolean =>
154	  steps.slice(0, index).some((step) => step.op === "quote");
155	
156	const insuranceValues: Record<string, number> = {
157	  sword: 1000,
158	  amulet: 600,
159	  staff: 800,
160	  potion: 400,
161	  rune: 250,
162	  moonstone: 250,
163	};
164	
165	const DEDUCTIBLE = 100;
166	
167	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
168	
169	const processClaim = (step: ClaimStep, scenario: Scenario): ClaimResult => {
170	  const policyStep = scenario.steps[step.policy] as QuoteStep;
171	  const insuranceSum = policyStep.items.reduce(
172	    (sum, item) => sum + insuranceValues[item.type],
173	    0
174	  );
175	  const cap = 2 * insuranceSum;
176	  const rawPayout = step.incident.damages.reduce(
177	    (total, damage) => total + damagePayout(damage),
178	    0
179	  );
180	  const payout = Math.floor(rawPayout);
181	  return { payout, remainingCap: cap - payout };
182	};
183	
184	export function runScenario(scenario: Scenario): ScenarioResult {
185	  const results = scenario.steps.map((step, index): StepResult => {
186	    if (step.op === "claim") {
187	      return processClaim(step, scenario);
188	    }
189	    const isFollowUp = isFollowUpQuote(scenario.steps, index);
190	    return {
191	      premium: quotePremium(step.items, scenario.customer, isFollowUp),
192	    };
193	  });
194	  return { results };
195	}
